def num_distinct(s: str, t: str) -> int:
    """Count distinct subsequences of s that equal t."""
    if not t:
        return 1
    if not s:
        return 0

    n, m = len(s), len(t)
    dp = [0] * (m + 1)
    dp[0] = 1  # One way to form empty t

    for i in range(n):
        for j in range(m, 0, -1):
            if s[i] == t[j - 1]:
                dp[j] += dp[j - 1]

    return dp[m]
